export const MetricsIllustration = ({
  variant = 'default',
  ...props
}: React.SVGProps<SVGSVGElement> & { variant?: IllustrationVariant }) => {
  const { resolvedTheme } = useTheme();
  const theme = (resolvedTheme as Theme) ?? 'light';

  return (
    <ClientOnly fallback={<MetricsIllustrationSVG theme="light" variant={variant} {...props} />}>
      <MetricsIllustrationSVG theme={theme} variant={variant} {...props} />
    </ClientOnly>
  );
};
